// main.js — bootstraps the prototype. Wires: capability gates → renderer (via factory) →
// waypoints → scroll choreographer → state machine → renderer.setFrame each tick. Cursor + dust
// are independent. Everything degrades gracefully (reduced-motion / no-WebGL / touch).

import './styles/stage.css';
import { resolveCapabilities } from './a11y/capability.js';
import { mountFallback } from './a11y/Fallback.js';
import { createRenderer } from './render/ApeRendererFactory.js';
import { WaypointController } from './engine/WaypointController.js';
import { ApeStateMachine } from './engine/ApeStateMachine.js';
import { ScrollChoreographer } from './engine/ScrollChoreographer.js';
import { GridOverlay } from './engine/GridOverlay.js';
import { BinaryDustField } from './cursor/BinaryDustField.js';

function boot() {
  const caps = resolveCapabilities();
  const apeLayer = document.getElementById('ape-layer');

  // Dev: press 'g' to toggle the grid + authored landing cells (for tuning layout.js).
  new GridOverlay().start();

  // Cursor: use the normal OS cursor (the banana cursor is disabled).

  // No jump engine under reduced-motion / no-WebGL — show the static perched monkey.
  if (!caps.motion) {
    mountFallback();
    return;
  }

  const { renderer } = createRenderer();
  if (!renderer) {
    mountFallback();
    return;
  }

  const waypoints = new WaypointController('.panel');
  const stateMachine = new ApeStateMachine(waypoints);

  renderer.mount(apeLayer).then(() => {
    waypoints.measure();
    // Dev hook: lets us 'self-play' the jump by sampling frameAt(progress) without scrolling.
    window.__sm = stateMachine;
    window.__wp = waypoints;

    // Binary dust bursts at each landing (tied to the jump, not the cursor).
    const dust = new BinaryDustField();
    dust.start();
    window.__dust = dust; // dev hook: trigger a burst by hand for tuning/verification

    let progress = 0;
    const choreo = new ScrollChoreographer((p) => { progress = p; });
    choreo.start();

    let lastState = 'perch';
    let lastExit = 0;
    let landPos = null;
    function loop() {
      const frame = stateMachine.frameAt(progress);
      renderer.setFrame(frame);
      // Burst when the landing COMPLETES, not when it begins. During the 'land' phase the monkey
      // hovers at its final screen height while the page scrolls the element up to its feet; its
      // touchdown point settles to the exact spot (feet on the element) by the end. Tracking it
      // through 'land' and firing once on exit puts the dust ON the element, not ~80px above it.
      if (frame.state === 'land') {
        landPos = frame.screenPos;
      } else if (lastState === 'land' && landPos) {
        dust.emitBurst(landPos.x, landPos.y);
        landPos = null;
      }
      // exit: stream 1010s ONLY while the dissolve is actively progressing (scrolling forward),
      // so it never keeps emitting when parked at the bottom or scrolling back up.
      if (frame.state === 'exit' && frame.exit > lastExit + 0.0008 && frame.exit < 0.98) {
        dust.emitBurst(frame.screenPos.x, frame.screenPos.y, 8);
      }
      lastState = frame.state;
      lastExit = frame.exit;
      requestAnimationFrame(loop);
    }
    requestAnimationFrame(loop);

    let resizeRAF = 0;
    window.addEventListener('resize', () => {
      cancelAnimationFrame(resizeRAF);
      resizeRAF = requestAnimationFrame(() => {
        waypoints.measure();
        renderer.resize(window.innerWidth, window.innerHeight);
        choreo.refresh();
      });
    });
  });
}

if (document.readyState === 'loading') {
  document.addEventListener('DOMContentLoaded', boot);
} else {
  boot();
}
