// cursor/BinaryDustField.js — landing FX (Codex's lane; lightweight own-canvas stand-in).
//
// NOT tied to the cursor anymore: it emits a burst of blue "bit" dust + 1010 binary glyphs at
// the monkey's feet each time a jump LANDS on a section. Codex will reimplement on a Pixi
// ParticleContainer with the real sprite look.

const MAX = 400;
const DUST = '#4ea3ff';  // themed blue bit-dust (matches the monkey/moon)
const BIT = '#ffd23f';   // yellow 1010 glyphs (matches the banana)

export class BinaryDustField {
  constructor() {
    this.canvas = null; this.ctx = null;
    this.parts = [];
    this.raf = 0;
    this._tick = this._tick.bind(this);
    this._resize = this._resize.bind(this);
  }

  start() {
    const c = document.createElement('canvas');
    c.id = 'dust-canvas';
    c.setAttribute('aria-hidden', 'true');
    Object.assign(c.style, { position: 'fixed', inset: '0', zIndex: '45', pointerEvents: 'none' });
    document.body.appendChild(c);
    this.canvas = c; this.ctx = c.getContext('2d');
    this._resize();
    window.addEventListener('resize', this._resize);
    this.raf = requestAnimationFrame(this._tick);
  }

  _resize() {
    const dpr = Math.min(window.devicePixelRatio || 1, 2);
    this.canvas.width = window.innerWidth * dpr;
    this.canvas.height = window.innerHeight * dpr;
    this.ctx.setTransform(dpr, 0, 0, dpr, 0, 0);
  }

  /** Burst of blue bit-dust + Matrix-green 1010 glyphs at a landing point. */
  emitBurst(x, y, n = 26) {
    for (let i = 0; i < n; i++) {
      if (this.parts.length >= MAX) this.parts.shift();
      // Mostly 1/0 glyphs so the binary reads clearly; the rest is fine blue dust.
      const bit = Math.random() < 0.62;
      const side = Math.random() < 0.5 ? -1 : 1;
      const spd = 1.1 + Math.random() * 1.9;
      this.parts.push({
        x: x + (Math.random() - 0.5) * 12,
        y: y + Math.random() * 4,
        vx: side * spd * (0.5 + Math.random() * 0.5),
        vy: -0.3 - Math.random() * 1.0,
        life: 1, decay: 0.026 + Math.random() * 0.02,
        size: bit ? 11 + Math.random() * 4 : 2 + Math.random() * 2.5,
        bit, glyph: Math.random() < 0.5 ? '0' : '1',
      });
    }
  }

  _tick() {
    const ctx = this.ctx;
    if (!ctx) return;
    ctx.clearRect(0, 0, this.canvas.width, this.canvas.height);
    for (let i = this.parts.length - 1; i >= 0; i--) {
      const p = this.parts[i];
      p.x += p.vx; p.y += p.vy; p.vy += 0.12; p.life -= p.decay; // gravity
      if (p.life <= 0) { this.parts.splice(i, 1); continue; }
      ctx.globalAlpha = Math.max(0, p.life);
      if (p.bit) {
        ctx.fillStyle = BIT;
        ctx.font = `${p.size}px ui-monospace, monospace`;
        ctx.fillText(p.glyph, p.x, p.y);
      } else {
        ctx.fillStyle = DUST;
        ctx.fillRect(p.x, p.y, p.size, p.size);
      }
    }
    ctx.globalAlpha = 1;
    this.raf = requestAnimationFrame(this._tick);
  }

  dispose() {
    cancelAnimationFrame(this.raf);
    window.removeEventListener('resize', this._resize);
    if (this.canvas) this.canvas.remove();
  }
}
