// engine/layout.js — THE JUMP LAYOUT (edit this to retune the monkey's path).
//
// The monkey now lands ON real page elements — not on abstract grid cells in empty space.
// Each LANDINGS entry names an element on the page (any CSS selector). The monkey touches
// down on that element's TOP edge, horizontally centred over it, at the exact scroll moment
// the element reaches the reading zone. Order = scroll order (top of page → bottom).
//
// Press the 'g' key in the browser to OUTLINE every target element + show the grid net, so
// you can see precisely where each jump lands and retune by eye.

// THE JUMP PATH — the elements the monkey hops onto, in order. Remove / reorder / add lines
// to retune the path. `target` is matched with document.querySelector (first match wins).
// `viewportY` (optional, 0..1) sets how far down the screen THAT landing happens, so each hop
// lands at a distinct height (otherwise every landing stacks at the same vertical line).
// viewportY values are spread wide and the two left panels (#aside/#zigzag) and the two centred
// panels (#servizi/#contatti) get very different heights, so no two landings stack on the same
// spot — the monkey (and its dust) travels the whole screen instead of hovering in one band.
export const LANDINGS = [
  { target: '#aside h2',    viewportY: 0.24 },  // "Like the moon, always at your side."  (left, high)
  { target: '#binary h2',   viewportY: 0.56 },  // "1010 = binary."                       (right, low)
  { target: '#zigzag h2',   viewportY: 0.42 },  // "Right to left, section to section."   (left, mid)
  { target: '#servizi h2',  viewportY: 0.66 },  // "What we do"                           (centre, low)
  { target: '#contatti h2', viewportY: 0.30 },  // "Say hi"                               (centre, high)
];

// Fine-tuning knobs shared by every landing.
export const LAND_TUNE = {
  // Where in the viewport (0 = top, 1 = bottom) a landing happens — i.e. how far down the
  // screen the target element sits at the instant the monkey touches it. ~0.42 = a touch
  // above centre, so the monkey perches on the heading while it's comfortably in view.
  viewportY: 0.42,
  // Gap (px) the feet sit above the element's top edge, so the monkey stands ON it
  // rather than overlapping the text.
  footGap: 8,
};
