// engine/WaypointController.js — turns real page ELEMENTS into jump waypoints + arcs.
//
// The monkey lives on a fixed full-viewport overlay; the page scrolls underneath it. For each
// element in layout.js LANDINGS we compute two things:
//   (a) the scroll position S at which that element's top edge reaches the reading zone, and
//   (b) the on-screen point of that top edge at that exact scroll moment.
// The monkey lands at (b) when the page is scrolled to (a). Because page scroll maps linearly
// to progress (ScrollChoreographer: top-top → bottom-bottom), the landing is pixel-exact: the
// feet touch the element's top edge ON the real scrolled page — never in empty gutter space.
//
// Timing is therefore NON-UNIFORM: each segment's share of progress is set by where its target
// actually sits on the page, not an even split. Renderer-agnostic: pure geometry.

import { LANDINGS, LAND_TUNE } from './layout.js';

const clamp = (v, a, b) => Math.max(a, Math.min(b, v));
const easeInOutCubic = (t) => (t < 0.5 ? 4 * t * t * t : 1 - Math.pow(-2 * t + 2, 3) / 2);
const easeOutCubic = (t) => 1 - Math.pow(1 - t, 3);
const easeOutQuart = (t) => 1 - Math.pow(1 - t, 4);
const heavyFall = (t) => {
  const tt = clamp(t, 0, 1);
  return tt * tt * (2.7 - 1.7 * tt);
};

export class WaypointController {
  constructor(panelSelector = '.panel') {
    this.panelSelector = panelSelector;
    /** @type {{x:number,y:number}[]} */ this.anchors = [];
    /** @type {number[]} global scroll-progress (0..1) at each anchor */ this.boundaries = [];
    /** @type {{p0:{x,y},c:{x,y},p1:{x,y},dx:number,dy:number,arc:number,isDrop:boolean,isExit:boolean}[]} */ this.segments = [];
  }

  /** (Re)measure anchors + arcs from the current layout. Call on load + resize. */
  measure() {
    const W = window.innerWidth;
    const H = window.innerHeight;
    const sx = window.scrollX;
    const sy = window.scrollY;
    const maxScroll = Math.max(1, document.documentElement.scrollHeight - H);
    const landVY = LAND_TUNE.viewportY;
    const footGap = LAND_TUNE.footGap;

    // Start perch: the monkey sits on the moon/bit (matches the CSS #moonWrap position).
    const moonY = H * 0.46 + Math.min(W * 0.18, 120) * 0.55;
    const moonPoint = { x: W * 0.5, y: moonY };

    // Resolve each LANDING element → its on-screen landing point + the scroll progress at
    // which it should be touched. Missing elements are skipped (so layout.js is forgiving).
    const landings = [];
    LANDINGS.forEach((cfg) => {
      const el = document.querySelector(cfg.target);
      if (!el) return;
      const r = el.getBoundingClientRect();
      const topDoc = r.top + sy;                 // element top in document space (scroll-independent)
      const cxDoc = r.left + sx + r.width / 2;   // element horizontal centre
      // Where down the screen this landing sits — per-landing override, else the shared default.
      const vy = typeof cfg.viewportY === 'number' ? cfg.viewportY : landVY;
      // Scroll position where the element's top edge sits at vy of the viewport.
      const S = clamp(topDoc - vy * H, 0, maxScroll);
      const p = S / maxScroll;
      // Feet on the element's top edge at that scroll moment (viewport-space).
      const y = topDoc - S - footGap;
      landings.push({ x: cxDoc, y, p });
    });

    // Order by scroll position; keep progress strictly increasing so segments are well-formed
    // and leave headroom at the end for the exit leap.
    landings.sort((a, b) => a.p - b.p);

    const anchors = [moonPoint];
    const boundaries = [0];
    let prevP = 0;
    landings.forEach((l) => {
      const p = clamp(Math.max(prevP + 0.03, l.p), 0, 0.96);
      anchors.push({ x: l.x, y: l.y });
      boundaries.push(p);
      prevP = p;
    });

    // Exit: leap up off the top-centre and dissolve into 1010.
    anchors.push({ x: W * 0.5, y: -H * 0.22 });
    boundaries.push(1);

    this.anchors = anchors;
    this.boundaries = boundaries;
    this.segments = [];
    for (let i = 0; i < anchors.length - 1; i++) {
      const p0 = anchors[i];
      const p1 = anchors[i + 1];
      const dx = p1.x - p0.x;
      const dy = p1.y - p0.y;
      const isExit = i === anchors.length - 2;
      const isDrop = !isExit && dy > H * 0.22;
      const arc = isExit ? H * 0.40 : isDrop ? clamp(8 + Math.abs(dx) * 0.025, 14, 28) : clamp(16 + Math.abs(dx) * 0.05, 20, 46);
      const c = { x: (p0.x + p1.x) / 2, y: Math.min(p0.y, p1.y) - arc };
      this.segments.push({ p0, c, p1, dx, dy, arc, isDrop, isExit });
    }
  }

  get segmentCount() {
    return this.segments.length;
  }

  /**
   * Resolve a global scroll progress (0..1) to a monkey position + motion hints.
   * @param {number} progress
   * @returns {{x:number,y:number, t:number, seg:number, facing:'left'|'right', vy:number, exitT:number}}
   */
  positionAt(progress) {
    const segs = this.segments;
    const B = this.boundaries;
    const n = segs.length;
    if (n === 0) return { x: 0, y: 0, t: 0, seg: 0, facing: 'right', vy: 0, exitT: 0 };

    // Locate the segment whose progress span contains `progress` (boundaries are non-uniform).
    const p = clamp(progress, 0, 1);
    let seg = 0;
    while (seg < n - 1 && p > B[seg + 1]) seg++;
    const span = Math.max(1e-6, B[seg + 1] - B[seg]);
    const t = clamp((p - B[seg]) / span, 0, 1);
    const s = segs[seg];
    const apexY = s.c.y;

    // Exit segment: monotonic eased rise to the top-centre (visible), where it dissolves.
    if (s.isExit) {
      const rt = Math.min(t / 0.5, 1); // the leap-away completes by exitT ~0.5, then it's gone
      const ex = s.p0.x + (s.p1.x - s.p0.x) * easeInOutCubic(rt);
      const ey = s.p0.y + (s.p1.y - s.p0.y) * easeOutQuart(rt); // rise fast, then settle at the top
      return { x: ex, y: ey, t, seg, facing: s.dx >= 0 ? 'right' : 'left', vy: -1, exitT: t };
    }

    // Horizontal: ease-in-out so the monkey accelerates off launch and decelerates into landing.
    const x = s.p0.x + (s.p1.x - s.p0.x) * (s.isDrop ? easeOutCubic(t) : easeInOutCubic(t));

    if (s.isDrop) {
      const ledgeT = 0.12;
      const lipY = s.p0.y - s.arc;
      let y, vy;
      if (t < ledgeT) {
        const tt = t / ledgeT;
        y = s.p0.y + (lipY - s.p0.y) * easeOutCubic(tt);
        vy = -0.25 * (1 - tt);
      } else {
        const tt = (t - ledgeT) / (1 - ledgeT);
        y = lipY + (s.p1.y - lipY) * heavyFall(tt);
        vy = clamp(0.18 + tt * 1.05, -1, 1);
      }
      const facing = s.dx === 0 ? 'right' : s.dx > 0 ? 'right' : 'left';
      return { x, y, t, seg, facing, vy, exitT: 0 };
    }

    // Vertical: asymmetric jump — floaty rise to the apex (easeOut), quicker fall (easeIn).
    // vy is normalized [-1,1]: -1 fast rising, 0 at apex, +1 fast falling.
    const peak = 0.36;
    let y, vy;
    if (t < peak) {
      const tt = t / peak;
      y = s.p0.y + (apexY - s.p0.y) * easeOutCubic(tt);
      vy = -(1 - tt);
    } else {
      const tt = (t - peak) / (1 - peak);
      y = apexY + (s.p1.y - apexY) * heavyFall(tt);
      vy = clamp(0.12 + tt * 0.95, -1, 1);
    }

    const facing = s.dx === 0 ? 'right' : s.dx > 0 ? 'right' : 'left';
    return { x, y, t, seg, facing, vy, exitT: 0 };
  }
}
